def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            base = np.sin(ratio * np.pi) ** 2 + np.cos(capacity % 10)
            for k in range(1, 15):
                temp = (base * (k ** 1.5) + np.log1p(ratio * k)) / (k + ratio)
                if k % 4 == 0:
                    temp *= 0.85
                else:
                    temp *= 1.15
                score += temp
            if (capacity + item) % 4 == 0 or (capacity * 2 - item) % 7 == 0:
                score *= 0.75
            if score > 9:
                score /= 3
            if capacity > 500:
                score /= (np.log1p(capacity) * 1.5)
        elif 0.05 <= ratio < 0.15:
            prod = 1
            for n in range(1, int(min(capacity, 20)) + 2):
                prod *= (ratio + n / (n * 0.5 + 1))
                if prod > 5e6:
                    prod = np.sqrt(prod)
                    break
            mod_val = int(prod * 1.3) % 350
            score += np.cbrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and ((item * 3) % 2 == 0):
                score += 6.7
            else:
                score -= 1.2
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x ** 3) % 1) * (x ** 2.3)
            score += extra_sum / 6
            if capacity < 10:
                score *= 1.8
        elif 0.15 <= ratio <= 0.4:
            for m in range(1, 10):
                increment = (ratio ** (m + 1)) * (m ** 3.1) / ((m + 3) ** 1.1)
                score += increment
            remainder = abs(capacity - item)
            if remainder < 5:
                score += 12 + remainder * 0.6
            else:
                score -= remainder
            if score < -7:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 18:
                score /= 4
        elif 0.4 < ratio <= 0.75:
            penalty_base = 0
            for p in range(1, 14):
                power = (ratio - 0.4) ** p
                penalty_base += power * (p ** 1.8)
                if penalty_base > 75:
                    penalty_base = np.log1p(penalty_base) * 2
                    break
            score = penalty_base * 10
            if capacity < item * 1.2:
                score += 20
            if (int(capacity * 4) % 8 == 0) and (int(item * 7) % 9 == 0):
                score -= 8
            if score < 0:
                score *= -1.2
                score += 10
            if score > 110:
                score = 110
            for z in range(1, 8):
                factor = ((ratio * z) % 1) * (z * 1.3)
                score += factor
        elif 0.75 < ratio <= 1.25:
            penalty_ext = 0
            diff = ratio - 0.75
            for q in range(1, 15):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 0.7)
                if penalty_ext > 2000:
                    penalty_ext = np.sqrt(penalty_ext) * 15
                    break
            score = penalty_ext * 9
            if capacity < item * 1.5:
                score += 25
            if (int(capacity * 6) % 3 == 0) and (int(item * 10) % 7 == 0):
                score -= 10
            for z in range(1, 10):
                score += ((diff / (z + 0.3)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.7
            if score > 1500:
                score = 1500
            if capacity < 3:
                score *= 2.5
        elif 1.25 < ratio <= 2.0:
            super_penalty = 0
            diff = ratio - 1.25
            for r in range(1, 18):
                term = ((diff) ** r) * (r ** 3.7)
                if term > 20000:
                    term = np.sqrt(term) * 1.8
                super_penalty += term
                if super_penalty > 1e6:
                    super_penalty = np.log1p(super_penalty) * 50
                    break
            score = super_penalty * 18
            if capacity < item * 2.2:
                score += 40
            if (int(capacity * 11) % 6 == 0) and (int(item * 15) % 8 == 0):
                score -= 12
            for w in range(3, 10):
                score += ((diff / w) % 1) * (w * 3)
            if score < 0:
                score = abs(score) * 0.8 + 6
            if score > 3500:
                score = 3500
            if capacity > 100:
                score /= (np.log1p(capacity) + 2)
        else:
            mega_penalty = 0
            diff = ratio - 2.0
            for s in range(1, 25):
                term = ((diff) ** s) * (s ** 4)
                if term > 50000:
                    term = np.sqrt(term) * 2.5
                mega_penalty += term
                if mega_penalty > 5e6:
                    mega_penalty = np.log1p(mega_penalty) * 100
                    break
            score = mega_penalty * 22
            if capacity < item * 3.0:
                score += 60
            if (int(capacity * 17) % 5 == 0) and (int(item * 23) % 11 == 0):
                score -= 15
            for v in range(3, 15):
                score += ((diff / v) % 1) * (v * 4)
            if score < 0:
                score = abs(score) * 0.9 + 8
            if score > 5000:
                score = 5000
            if capacity < 1:
                score *= 3
        if abs(score) > 2500:
            score = np.sign(score) * 2500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 1.0
    else:
        q25, q50, q75 = np.percentile(finite_priorities, [25, 50, 75])
        top_count = np.sum(finite_priorities > q75)
        median_val = q50
        fill_value = (np.max(finite_priorities) + np.min(finite_priorities)) * (10 + top_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 1.0
    return priorities
